import React, { useEffect, useState } from "react";
import axios from "axios";

const API_BASE = "http://localhost:5000/api/reviews";

const AdminReviews = () => {
  const [reviews, setReviews] = useState([]);
  const [loading, setLoading] = useState(true);
  const [replyText, setReplyText] = useState("");
  const [activeReview, setActiveReview] = useState(null);

  useEffect(() => {
    fetchReviews();
  }, []);

  const fetchReviews = async () => {
    setLoading(true);
    try {
      const res = await axios.get("http://localhost:5000/api/products");
      let allReviews = [];

      for (const p of res.data.products || []) {
        const rv = await axios.get(`${API_BASE}/${p._id}`);
        if (rv.data.data.length > 0) {
          allReviews.push(
            ...rv.data.data.map((r) => ({ ...r, productName: p.name }))
          );
        }
      }
      setReviews(allReviews);
    } catch (err) {
      console.error("❌ Lỗi lấy đánh giá:", err);
    }
    setLoading(false);
  };

  const submitReply = async () => {
    if (!activeReview) return;

    try {
      await axios.put(
        `${API_BASE}/${activeReview._id}/reply`,
        { reply: replyText },
        {
          headers: {
            Authorization: `Bearer ${localStorage.getItem("token")}`,
          },
        }
      );

      alert("Phản hồi thành công!");
      setReplyText("");
      setActiveReview(null);
      fetchReviews();
    } catch (err) {
      console.error("❌ Lỗi reply:", err);
      alert("Không thể phản hồi.");
    }
  };

  if (loading)
    return <div className="text-center mt-20 text-gray-500 text-lg">
      Đang tải đánh giá...
    </div>;

  return (
    <div className="p-6 bg-white rounded-lg shadow border max-w-4xl mx-auto">
      <h2 className="text-xl font-semibold mb-6">
        Quản lý đánh giá sản phẩm
      </h2>

      {reviews.length === 0 && (
        <p className="text-gray-500">Chưa có đánh giá nào.</p>
      )}

      <div className="space-y-5">
        {reviews.map((rv) => (
          <div
            key={rv._id}
            className="border rounded-lg p-4 bg-gray-50"
          >
            <div className="flex justify-between">
              <p className="font-medium">
                {rv.user?.name} — {rv.rating}★
              </p>
              <p className="text-sm text-gray-500">{rv.productName}</p>
            </div>

            <p className="mt-1">{rv.comment}</p>

            {rv.adminReply && (
              <div className="mt-2 p-3 bg-white border rounded">
                <p className="font-medium text-gray-700">Phản hồi:</p>
                <p>{rv.adminReply}</p>
              </div>
            )}

            <button
              className="mt-3 px-4 py-1 bg-gray-800 text-white text-sm rounded hover:bg-black"
              onClick={() => {
                setActiveReview(rv);
                setReplyText(rv.adminReply || "");
              }}
            >
              Trả lời
            </button>
          </div>
        ))}
      </div>

      {/* POPUP */}
      {activeReview && (
        <div className="fixed inset-0 bg-black bg-opacity-40 flex justify-center items-center">
          <div className="bg-white p-6 rounded-lg w-[380px] shadow-lg">

            <h3 className="text-lg font-semibold mb-3">
              Trả lời đánh giá
            </h3>

            <textarea
              value={replyText}
              onChange={(e) => setReplyText(e.target.value)}
              rows={3}
              className="w-full border rounded p-2"
            />

            <div className="flex justify-end gap-3 mt-4">
              <button
                className="px-4 py-1 border rounded"
                onClick={() => setActiveReview(null)}
              >
                Hủy
              </button>

              <button
                className="px-4 py-1 bg-gray-800 text-white rounded hover:bg-black"
                onClick={submitReply}
              >
                Gửi
              </button>
            </div>

          </div>
        </div>
      )}
    </div>
  );
};

export default AdminReviews;
